void process_admin_request(privilege_request_t *req)
{
    int ret = -EINVAL;
    
    printk("[ADMIN] Processing request: op=%d from tid=%p (privilege=%d)\n",
           req->operation, req->requester_tid, req->requester_privilege);
    
    switch (req->operation) {
        case OP_WRITE_FLASH:
            if (req->requester_privilege >= PRIVILEGE_ADMIN) {
                ret = admin_write_flash(req->offset, req->data, req->data_len);
            } else {
                printk("[ADMIN] Access denied: insufficient privilege for flash write\n");
                ret = -EACCES;
            }
            break;
            
        case OP_MODIFY_CONFIG:
            if (req->requester_privilege >= PRIVILEGE_ADMIN) {
                ret = admin_modify_config((system_config_t *)req->data);
            } else {
                printk("[ADMIN] Access denied: insufficient privilege for config modify\n");
                ret = -EACCES;
            }
            break;
            
        case OP_READ_CONFIG:
            ret = admin_read_config((system_config_t *)req->data);
            break;
            
        default:
            printk("[ADMIN] Unknown operation: %d\n", req->operation);
            ret = -ENOTSUP;
            break;
    }
    
    req->result = ret;
    k_sem_give(&req->completion);
}

