int submit_privilege_request(task_context_t *ctx, uint8_t operation, 
                             void *data, size_t data_len, uint32_t offset)
{
    privilege_request_t req;
    int ret;
    
    req.operation = operation;
    req.requester_privilege = ctx->privilege_level;
    req.requester_tid = ctx->tid;
    req.data = data;
    req.data_len = data_len;
    req.offset = offset;
    req.result = -EINVAL;
    
    k_sem_init(&req.completion, 0, 1);
    
    privilege_request_t *req_ptr = &req;
    ret = k_msgq_put(&admin_msgq, &req_ptr, K_NO_WAIT);
    if (ret != 0) {
        printk("[USER] Failed to submit request: %d\n", ret);
        return ret;
    }
    
    k_sem_take(&req.completion, K_FOREVER);
    
    return req.result;
}

